def _load_pillow_font_from_candidates(font_size: int, candidates: list[str]):
    try:
        from PIL import ImageFont
    except Exception:
        return None
    font_size = max(8, int(font_size))
    seen = set()
    for font_path in candidates:
        if not font_path or font_path in seen:
            continue
        seen.add(font_path)
        try:
            if os.path.exists(font_path):
                return ImageFont.truetype(font_path, font_size)
        except Exception:
            continue
    try:
        return ImageFont.load_default()
    except Exception:
        return None

def _find_logo_font(font_size: int, prefer_cjk: bool = False):
    """寻找可用的品牌字体；中文/英文分别固定一套候选，保持 严谨医学插画风格一致。"""
    return _load_pillow_font_from_candidates(font_size, _cell_font_path_candidates(prefer_cjk=prefer_cjk, weight=600))


def _find_postprocess_font(font_size: int, prefer_cjk: bool = False, weight: int = 400):
    """后处理专用字体：中文固定中文字体族，英文固定英文字体族；只按字重切换同族候选。"""
    font_size = max(8, int(font_size))
    weight = int(weight or 400)
    return _load_pillow_font_from_candidates(font_size, _cell_font_path_candidates(prefer_cjk=prefer_cjk, weight=weight))



