def _quanlan_runtime_project_root() -> str:
    try:
        return os.path.dirname(os.path.abspath(__file__))
    except Exception:
        return os.getcwd()


def _is_quanlan_generated_logo_text(text: str | None) -> bool:
    value = str(text or "").strip().replace(" ", "")
    return value in {"QuanLanBrainScience®", "QuanLanBrainScience", "全澜脑科学®", "全澜脑科学"}


def _quanlan_logo_lang_from_text(text: str | None = None, default: str = "en") -> str:
    value = str(text or "").strip()
    if "全澜" in value or any("\u4e00" <= ch <= "\u9fff" for ch in value):
        return "zh"
    return "en" if str(default or "en").lower() not in {"zh", "cn"} else "zh"


def _quanlan_logo_asset_path(lang: str = "en") -> str:
    key = "zh" if str(lang or "en").lower() in {"zh", "cn", "chinese"} else "en"
    rel = QUANLAN_LOGO_ASSET_REL.get(key, QUANLAN_LOGO_ASSET_REL["en"])
    return os.path.join(_quanlan_runtime_project_root(), rel)


def _load_quanlan_logo_asset(lang: str = "en"):
    from PIL import Image
    path = _quanlan_logo_asset_path(lang)
    logo = Image.open(path).convert("RGBA")
    # Strengthened AC/alpha mask: keeps anti-aliased edges, removes near-zero dust, restores solid strokes.
    r, g, b, a = logo.split()
    a = a.point(lambda v: 0 if v < 3 else (255 if v > 245 else min(255, int(round(v * 1.10)))))
    return Image.merge("RGBA", (r, g, b, a))


def _apply_quanlan_logo_opacity(logo, opacity: int | float = 255):
    opacity = int(round(float(opacity)))
    opacity = max(0, min(255, opacity))
    if opacity >= 255:
        return logo
    r, g, b, a = logo.split()
    a = a.point(lambda v: int(round(v * opacity / 255.0)))
    from PIL import Image
    return Image.merge("RGBA", (r, g, b, a))


def _resize_quanlan_logo_asset(logo, *, target_w_px: int | None = None, target_h_px: int | None = None, max_w_px: int | None = None, max_h_px: int | None = None):
    from PIL import Image
    ow, oh = logo.size
    if ow <= 0 or oh <= 0:
        return logo
    scale = None
    if target_w_px and target_w_px > 0:
        scale = float(target_w_px) / float(ow)
    if target_h_px and target_h_px > 0:
        scale_h = float(target_h_px) / float(oh)
        scale = scale_h if scale is None else min(scale, scale_h)
    if scale is None:
        scale = 1.0
    if max_w_px and ow * scale > max_w_px:
        scale = float(max_w_px) / float(ow)
    if max_h_px and oh * scale > max_h_px:
        scale = float(max_h_px) / float(oh)
    scale = max(0.01, float(scale))
    nw, nh = max(1, int(round(ow * scale))), max(1, int(round(oh * scale)))
    if (nw, nh) == (ow, oh):
        return logo
    return logo.resize((nw, nh), Image.Resampling.LANCZOS)


def _paste_quanlan_logo_on_layer(layer, *, lang: str = "en", x: int | None = None, y: int | None = None, center_x: int | None = None, center_y: int | None = None, target_w_px: int | None = None, target_h_px: int | None = None, max_w_px: int | None = None, max_h_px: int | None = None, opacity: int | float = 255):
    """Paste transparent PNG logo by scaling + coordinates. Returns pasted bbox."""
    try:
        logo = _load_quanlan_logo_asset(lang)
        logo = _resize_quanlan_logo_asset(logo, target_w_px=target_w_px, target_h_px=target_h_px, max_w_px=max_w_px, max_h_px=max_h_px)
        logo = _apply_quanlan_logo_opacity(logo, opacity)
        lw, lh = logo.size
        if center_x is not None:
            x = int(round(float(center_x) - lw / 2.0))
        elif x is None:
            x = 0
        if center_y is not None:
            y = int(round(float(center_y) - lh / 2.0))
        elif y is None:
            y = 0
        layer.alpha_composite(logo, dest=(int(x), int(y)))
        return (int(x), int(y), int(x) + lw, int(y) + lh)
    except Exception:
        return (0, 0, 0, 0)


def _paste_quanlan_logo_on_draw(draw, **kwargs):
    try:
        layer = getattr(draw, "_image", None)
        if layer is None:
            return (0, 0, 0, 0)
        return _paste_quanlan_logo_on_layer(layer, **kwargs)
    except Exception:
        return (0, 0, 0, 0)


def _quanlan_logo_height_from_style(canvas_h: int, style: dict | None = None, fallback_ratio: float = 0.0331) -> int:
    style = style or {}
    ratio = float(style.get("visual_height_ratio_h", style.get("font_ratio_h", fallback_ratio)) or fallback_ratio)
    return max(10, int(round(canvas_h * ratio)))
