def stamp_content_page_logo(image_path: str, logger=None) -> bool:
    """按内容风格叠加内容页品牌；QuanLan/全澜 logo 只使用透明 PNG 图片。"""
    try:
        from PIL import Image
    except Exception:
        if logger:
            logger("⚠️ 缺少 Pillow，无法叠加统一内容页品牌。请运行：pip install pillow")
        return False
    try:
        if not os.path.exists(image_path):
            return False
        img = Image.open(image_path).convert("RGBA")
        w, h = img.size
        style = POSTPROCESS_STABLE_SPEC.get("content_logo_style", {}) if isinstance(globals().get("POSTPROCESS_STABLE_SPEC", None), dict) else {}
        mode = str(style.get("mode", "top_left") or "top_left").strip().lower()
        x_ratio = float(style.get("x_ratio", CONTENT_LOGO_X_RATIO))
        y_ratio = float(style.get("y_ratio", CONTENT_LOGO_Y_RATIO))
        max_width_ratio = float(style.get("max_width_ratio", 0.42) or 0.42)
        opacity = int(style.get("opacity", CONTENT_LOGO_OPACITY))
        logo_h = _quanlan_logo_height_from_style(h, style, fallback_ratio=float(style.get("font_ratio_h", CONTENT_LOGO_FONT_RATIO_H) or CONTENT_LOGO_FONT_RATIO_H))
        lang = str(style.get("asset_lang") or _quanlan_logo_lang_from_text(CONTENT_LOGO_TEXT, "en"))
        overlay = Image.new("RGBA", img.size, (0, 0, 0, 0))

        if _is_quanlan_generated_logo_text(CONTENT_LOGO_TEXT):
            if mode == "watermark_center":
                _paste_quanlan_logo_on_layer(overlay, lang=lang, center_x=int(round(w * x_ratio)), center_y=int(round(h * y_ratio)), target_h_px=logo_h, max_w_px=int(round(w * max_width_ratio)), opacity=opacity)
            elif mode == "bottom_center":
                bbox = _paste_quanlan_logo_on_layer(overlay, lang=lang, center_x=int(round(w * x_ratio)), y=0, target_h_px=logo_h, max_w_px=int(round(w * max_width_ratio)), opacity=opacity)
                ly = int(round(h * y_ratio - (bbox[3] - bbox[1])))
                overlay = Image.new("RGBA", img.size, (0, 0, 0, 0))
                _paste_quanlan_logo_on_layer(overlay, lang=lang, center_x=int(round(w * x_ratio)), y=ly, target_h_px=logo_h, max_w_px=int(round(w * max_width_ratio)), opacity=opacity)
            else:
                _paste_quanlan_logo_on_layer(overlay, lang=lang, x=int(round(x_ratio * w)), y=int(round(y_ratio * h)), target_h_px=logo_h, max_w_px=int(round(w * max_width_ratio)), opacity=opacity)
        else:
            # Non-QuanLan labels are intentionally not rendered here to avoid accidental font-logo recreation.
            return True

        out = Image.alpha_composite(img, overlay).convert("RGB")
        out.save(image_path, "PNG")
        if logger:
            logger(f"🔒 内容图品牌已用 PNG 图片锁定：mode={mode}, lang={lang}; {os.path.basename(image_path)}")
        return True
    except Exception as e:
        if logger:
            logger(f"⚠️ 内容图品牌后处理失败：{str(e)[:120]}")
        return False

def get_raw_image_backup_path(image_path: str) -> str:
    """返回同名 raw 原图备份路径；用于保证后处理可重复运行且不重复叠加。"""
    folder = os.path.dirname(os.path.abspath(image_path or ""))
    raw_dir = os.path.join(folder, "_raw")
    os.makedirs(raw_dir, exist_ok=True)
    return os.path.join(raw_dir, os.path.basename(image_path or "image.png"))



def ensure_raw_image_backup(image_path: str, logger=None) -> str:
    """第一次后处理时保存模型原始输出；以后不覆盖，避免把已盖章图片当 raw。"""
    raw_path = get_raw_image_backup_path(image_path)
    try:
        if image_path and os.path.exists(image_path) and not os.path.exists(raw_path):
            shutil.copy2(image_path, raw_path)
            if logger:
                logger(f"📦 已保存模型原始图备份：_raw/{os.path.basename(raw_path)}")

    except Exception as e:
        if logger:
            logger(f"⚠️ raw 原图备份失败：{str(e)[:120]}")
    return raw_path


def _open_postprocess_source(image_path: str, logger=None):
    """始终优先从 raw 原图开始后处理，保证重复运行不会越盖越厚。"""
    try:
        from PIL import Image
    except Exception:
        return None, ""
    raw_path = ensure_raw_image_backup(image_path, logger=logger)
    source_path = raw_path if os.path.exists(raw_path) else image_path
    try:
        return Image.open(source_path).convert("RGBA"), raw_path
    except Exception as e:
        if logger:
            logger(f"⚠️ 打开后处理源图失败：{str(e)[:120]}")
        return None, raw_path


def _rgb_to_rgba(rgb, alpha=255):
    return tuple(rgb[:3]) + (int(alpha),)



def _draw_centered_logo_chip(draw, *, center_x: int, center_y: int, font_size: int, box_w: int, box_h: int) -> tuple[int, int, int, int]:
    """绘制统一品牌色块；QuanLan/全澜 logo 使用透明 PNG 贴图。"""
    x0 = int(center_x - box_w / 2)
